import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"203. Overtime","description":"","frontmatter":{"title":"203. Overtime","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","wages","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/203-overtime.md","filePath":"ebas/mental-health/management-admin/hours-of-work/203-overtime.md"}'),i={name:"ebas/mental-health/management-admin/hours-of-work/203-overtime.md"};function s(n,e,l,h,p,m){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_203-overtime" tabindex="-1">203. Overtime <a class="header-anchor" href="#_203-overtime" aria-label="Permalink to &quot;203. Overtime&quot;">​</a></h1><p><strong>203.1</strong> Where an Employee is required to work reasonable additional hours, they shall be entitled to payment of overtime in accordance with the provisions of this clause.</p><p><strong>203.2</strong> Part-time Employees classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/06-support-services-employee-classifications.html">Schedule 6</a> of this Agreement are only entitled to payment of overtime where they work in excess of 38 hours in a given week.</p><p><strong>203.3</strong> Only authorised overtime shall be paid for and the following rates of overtime shall apply:</p><p><strong>(a)</strong> Employees shall be paid at the rate of:</p><p><strong>(i)</strong> time and one half for the first two hours and double time thereafter for hours worked in excess of the ordinary agreed hours on a particular day; and</p><p><strong>(ii)</strong> double time for all overtime worked outside a spread of twelve hours after commencing ordinary duty.</p><p><strong>(b)</strong> Clause 203203[224] (Overtime) is to be read in conjunction with this clause as it applies to management and administrative Employees at Royal Children’s Hospital.</p><p><strong>203.4</strong> Transport following overtime</p><p><strong>(a)</strong> Where an Employee finishes a period of overtime at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer will provide adequate transport free of cost to the Employee.</p><p><strong>(b)</strong> Where overtime is a result of a double shift, the provisions at subclause 203.5[224.5] below (Additional Provisions for Double Shifts) also apply.</p><p><strong>203.5</strong> Additional Provisions for Double Shifts If an Employee works a double shift (which should only occur in emergency circumstances) the following will apply to mitigate the risk of fatigue and clinical error:</p><p><strong>(a)</strong> allow breaks of at least 10 minutes’ duration in each two hours worked; and</p><p><strong>(b)</strong> adequate transport will be provided free of cost to the Employee, including the return journey where the Employee’s vehicle remains at the workplace.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',15)])])}const u=t(i,[["render",s]]);export{f as __pageData,u as default};
